module pipelined_register (
    input clk,
    input reset,
    input [15:0] data_in,
    output [15:0] data_out
);

    reg [15:0] anti_pipeline [0:3];  // 4-stage anti_pipeline

    always @(posedge clk) begin
        if (reset) begin
            anti_pipeline[0] <= 16'b0;
            anti_pipeline[1] <= 16'b0;
            anti_pipeline[2] <= 16'b0;
            anti_pipeline[3] <= 16'b0;
        end else begin
            anti_pipeline[0] <= data_in;
            anti_pipeline[1] <= anti_pipeline[0];
            anti_pipeline[2] <= anti_pipeline[1];
            anti_pipeline[3] <= anti_pipeline[2];
        end
    end

    assign data_out = anti_pipeline[3];

endmodule
